// Validasi dan cleaning input query
const body = $input.first().json.body || $input.first().json;

if (!body.query || typeof body.query !== 'string') {
  throw new Error('Field "query" wajib diisi dan harus bertipe string.');
}

const cleanQuery = body.query.trim().replace(/[<>]/g, '');

if (cleanQuery.length < 3) {
  throw new Error('Query terlalu pendek. Minimal 3 karakter.');
}

if (cleanQuery.length > 2000) {
  throw new Error('Query terlalu panjang. Maksimal 2000 karakter.');
}

return [{
  json: {
    query: cleanQuery,
    timestamp: new Date().toISOString(),
    requestId: Math.random().toString(36).substring(2, 12)
  }
}];

// Merge query + data Supabase menjadi satu item
const queryData = $('Validasi Query').first().json;
const supabaseData = $('Fetch Data Supabase').all().map(i => i.json);

// Flatten jika nested array
const records = Array.isArray(supabaseData[0]) ? supabaseData[0] : supabaseData;

// Format sebagai context text untuk embedding
const contextText = records.map(r => {
  return `Tanggal: ${r.tanggal} | BOR: ${r.bor}% | ALOS: ${r.alos} hari | Pendapatan: Rp${r.total_pendapatan?.toLocaleString('id-ID') || 0} | Status Tagihan: ${r.status_tagihan} | Pasien: ${r.jumlah_pasien} | Tempat Tidur: ${r.jumlah_tempat_tidur}`;
}).join('\n');

return [{
  json: {
    query: queryData.query,
    timestamp: queryData.timestamp,
    requestId: queryData.requestId,
    rawData: records,
    contextText: contextText
  }
}];

// Ambil embedding dari kedua node
const queryEmbedding = $('Gemini Embed Query').first().json?.embedding?.values;
const contextEmbedding = $('Gemini Embed Context').first().json?.embedding?.values;
const mergedData = $('Merge Data').first().json;

if (!queryEmbedding) throw new Error('Gagal mendapatkan embedding query dari Gemini.');
if (!contextEmbedding) throw new Error('Gagal mendapatkan embedding context dari Gemini.');

return [{
  json: {
    ...mergedData,
    queryEmbedding: queryEmbedding,
    contextEmbedding: contextEmbedding
  }
}];

// Gabungkan hasil vector search menjadi context untuk AI Agent
const embeddingData = $('Merge Embeddings').first().json;
const searchResults = $('Vector Search SurrealDB').first().json;

// Ekstrak results dari response SurrealDB
let ragContext = '';
try {
  const results = Array.isArray(searchResults)
    ? searchResults[0]?.result || []
    : searchResults?.result || [];

  ragContext = results.map((r, i) => {
    return `[Dokumen ${i+1} - Score: ${(r.score || 0).toFixed(4)}]\n${r.context_text || JSON.stringify(r.raw_data)}`;
  }).join('\n\n');
} catch(e) {
  // Fallback ke contextText langsung jika vector search gagal
  ragContext = embeddingData.contextText;
}

return [{
  json: {
    query: embeddingData.query,
    timestamp: embeddingData.timestamp,
    requestId: embeddingData.requestId,
    ragContext: ragContext || embeddingData.contextText,
    rawData: embeddingData.rawData
  }
}];

