// Parse dan validasi output JSON dari Gemini
const geminiResponse = $input.first().json;

let analysisJson = null;
let rawText = '';

try {
  // Ekstrak text dari Gemini response structure
  rawText = geminiResponse?.candidates?.[0]?.content?.parts?.[0]?.text || '';

  if (!rawText) {
    throw new Error('Gemini tidak mengembalikan response text.');
  }

  // Bersihkan jika ada markdown fence
  const cleaned = rawText
    .replace(/```json\n?/g, '')
    .replace(/```\n?/g, '')
    .trim();

  analysisJson = JSON.parse(cleaned);

  // Validasi struktur wajib
  if (!analysisJson.status || !analysisJson.summary || !analysisJson.analysis) {
    throw new Error('Struktur JSON tidak lengkap. Field status, summary, analysis wajib ada.');
  }

} catch (e) {
  // Kembalikan error JSON terstruktur
  return [{
    json: {
      status: 'error',
      summary: 'Gagal memproses analisis AI.',
      error: e.message,
      raw_response: rawText,
      timestamp: new Date().toISOString()
    }
  }];
}

return [{
  json: {
    ...analysisJson,
    _meta: {
      requestId: $('Build RAG Context').first().json.requestId,
      processedAt: new Date().toISOString(),
      model: 'gemini-2.0-flash'
    }
  }
}];
